uvicorn==0.23.2
```

## 2. Frontend (Next.js)

Now let's set up the Next.js frontend to fetch and display the Wi-Fi stats.

First, create `frontend/package.json`:

```json
{
  "name": "wifi-stats",
  "version": "1.0.0",
  "scripts": {
    "dev": "next dev",
    "build": "next build",
    "start": "next start"
  },
  "dependencies": {
    "next": "14.0.2",
    "react": "18.2.0",
    "react-dom": "18.2.0"
  }
}
```

Create the page layout file `frontend/app/layout.tsx`:

```typescript
import './globals.css'

export const metadata = {
  title: 'Wi-Fi Stats',
}

export default function RootLayout({ children }) {
  return (
    <html lang="en">
      <body>{children}</body>
    </html>
  )
}
```

Create the main page that fetches and displays WiFi stats `frontend/app/page.tsx`:

```typescript
'use client'

import { useState, useEffect } from 'react';

const Card = ({ title, value }) => (
  <div className="card">
    <h3>{title}</h3>
    <p>{value ?? 'N/A'}</p>
  </div>
);

export default function Home() {
  const [wifiStats, setWifiStats] = useState({
    ssid: '',
    bssid: '',
    rssi: null,
    channel: null,
    tx_rate: null,
    security: ''
  });

  useEffect(() => {
    async function fetchWifiData() {
      try {
        const response = await fetch('http://localhost:8000/api/wifi');
        if (response.ok) {
          const data = await response.json();
          setWifiStats(data);
        }
      } catch (error) {
        console.error("Failed to fetch Wi-Fi stats:", error);
      }
    }

    // Fetch every 3 seconds
    const intervalId = setInterval(fetchWifiData, 3000);

    // Initial call
    fetchWifiData();

    return () => clearInterval(intervalId);
  }, []);

  return (
    <div className="container">
      <Card title="SSID" value={wifiStats.ssid} />
      <Card title="BSSID" value={wifiStats.bssid} />
      <Card title="Signal Strength (RSSI)" value={`${wifiStats.rssi ?? 'N/A'} %`} />
      <Card title="Channel" value={wifiStats.channel} />
      <Card title="Tx Rate" value={`${wifiStats.tx_rate ?? 0} Mbps`} />
      <Card title="Security" value={wifiStats.security} />
    </div>
  );
}
```

